import './ProgressButton.scss';

import { Button, resolveVariant } from ':components/Button/Button';
import { Icon } from ':components/Icon';
import { classNames } from ':helpers/classnames';
import { useDebounceCallback } from ':helpers/use-debounce-callback';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import {
	colorBackgroundBrand,
	colorButtonOverlayBackground,
	colorStatusError,
	colorTextBlackActive,
} from '@beeline/design-tokens/js/tokens';
import type { RefCallback } from 'react';
import React, { forwardRef, useEffect, useMemo, useRef, useState } from 'react';
import { DEFAULT_SETTINGS } from './consts';
import type { LoadingStateTypes, ProgressButtonProps, SVGPathSettings } from './ProgressButton.types';
import { calcPathDefinition, calcSettings, isErrorObject } from './utils';

export const ProgressButton = forwardRef<HTMLButtonElement, ProgressButtonProps>(
	(
		{
			determinateMode = false,
			progress = 0,
			size = 'medium',
			statusDelayTime = 4000,
			className,
			variant = 'primary',
			children,
			startIcon,
			endIcon,
			onClick,
			disabled,
			state,
			...props
		},
		ref,
	) => {
		const resolvedVariant = resolveVariant(variant);
		const svgRef = useRef<SVGSVGElement>(null);
		const pathRef = useRef<SVGPathElement>(null);
		const buttonRef = useRef<HTMLButtonElement>(null);

		const [_progress, _setProgress] = useState<number>(determinateMode ? progress : 0);
		const [statusIcon, setStatusIcon] = useState<Icons>(Icons.Check);
		const [isError, setIsError] = useState(false);
		const [settings, setSettings] = useState<SVGPathSettings>(DEFAULT_SETTINGS);

		const [toDefaultStateWithDelay, cancelToDefaultStateWithDelay] = useDebounceCallback(() => {
			if (statusDelayTime === -1) {
				return;
			}
			_setProgress(0);
			setIsError(false);
		}, statusDelayTime);

		// текущий статус загрузки, реагирует на изменение прогресса и ошибку
		const loadingState = useMemo<LoadingStateTypes>(() => {
			if (state) {
				return state;
			}
			if (isError) {
				return 'error';
			}

			if (_progress <= 0) {
				return 'default';
			}

			if (_progress > 0 && _progress < 100) {
				return 'loading';
			}

			if (_progress >= 100) {
				return 'success';
			}
		}, [isError, _progress, state]);

		// присваиваем current и внутренней ссылке на кнопку и той, что приходит в пропсах
		// нужно для корректной работы и когда пользователю нужен внешний ref и когда нет
		const setButtonRefHandler: RefCallback<HTMLButtonElement> = (buttonElement): void => {
			if (buttonElement) {
				if (ref && 'current' in ref) {
					ref.current = buttonElement;
				}
				buttonRef.current = buttonElement;
			}
		};

		const isFinished = useMemo(() => loadingState === 'success' || loadingState === 'error', [loadingState]);

		const strokeColor = useMemo(() => {
			if (loadingState === 'error') {
				return colorStatusError;
			}

			if (loadingState === 'success') {
				return 'transparent';
			}

			switch (resolvedVariant) {
				case 'contained':
					return colorTextBlackActive;
				case 'outlined':
					return colorBackgroundBrand;
				case 'overlay':
					return colorButtonOverlayBackground;
				case 'danger':
					return colorStatusError;
				case 'accent-black':
					return colorTextBlackActive;
				case 'accent-white':
					return colorTextBlackActive;
				default:
					return 'transparent';
			}
		}, [resolvedVariant, loadingState]);

		const pathDefinition = useMemo<string>(() => calcPathDefinition(settings), [settings]);

		// Отслеживаем изменения размера окна только если включен fullWidth
		const [windowWidth, setWindowWidth] = useState<number>(window.innerWidth);
		const fullWidth = props?.fullWidth;
		useEffect(() => {
			// Если fullWidth не включен, не добавляем слушатель событий
			if (!fullWidth) {
				return;
			}

			const handleResize = () => {
				setWindowWidth(window.innerWidth);
			};

			window.addEventListener('resize', handleResize);
			return () => {
				window.removeEventListener('resize', handleResize);
			};
		}, [fullWidth]);

		/**
		 * Перерисовка анимации на основе новых размеров
		 */
		useEffect(() => {
			const calculatedSettings: SVGPathSettings = calcSettings(buttonRef);

			setSettings(calculatedSettings);
		}, [children, size, loadingState, buttonRef, fullWidth && windowWidth]);

		/**
		 * обновление прогресса при изменении пропса снаружи
		 * работает только в режиме определенной загрузки
		 * при цикличной загрузке прогрессом полностью управляет компонент
		 */
		useEffect(() => {
			if (determinateMode) {
				if (progress <= 0) {
					_setProgress(0);
				}

				if (progress > 0 && progress < 100) {
					_setProgress(progress);
				}

				if (progress >= 100) {
					_setProgress(100);
				}
			}
		}, [progress, determinateMode]);

		/**
		 * Управление отображением загрузки в зависимости от текущего {@link loadingState}
		 */
		useEffect(() => {
			switch (loadingState) {
				case 'default': {
					break;
				}

				case 'loading': {
					break;
				}

				case 'success': {
					setStatusIcon(Icons.Check);

					toDefaultStateWithDelay();

					break;
				}

				case 'error': {
					setStatusIcon(Icons.Refresh);

					toDefaultStateWithDelay();

					break;
				}

				default: {
					throw new Error(`Неизвестное состояние загрузки для ProgressButton: '${loadingState}'!`);
				}
			}
		}, [loadingState, toDefaultStateWithDelay]);

		const handleClick = (): void => {
			setIsError(false);
			cancelToDefaultStateWithDelay();

			// работая с зацикленным лоадером - управляем значением прогресса для отрисовки загрузки, обрабатываем ошибку
			if (!determinateMode && onClick) {
				_setProgress(3);
			}

			// в любом режиме обрабатываем резолв и ошибку
			onClick?.()
				.then(res => {
					// если пользователь обработает ошибку
					// и вернет значение из своего блока catch, то он придет сюда
					// если это все-таки ошибка - кидаем ошибку чтобы корректно обработать статус кнопки
					if (isErrorObject(res)) {
						throw res;
					}

					_setProgress(100);

					return res;
				})
				.catch(error => {
					setIsError(true);
				});
		};

		return (
			<Button
				data-testid="ProgressButton"
				ref={setButtonRefHandler}
				{...props}
				onClick={handleClick}
				size={size}
				variant={resolvedVariant}
				className={classNames(
					'dsb-button-progress',
					`dsb-button-progress--${loadingState}`,
					{
						'dsb_button__start-icon': !!startIcon,
						'dsb_button__end-icon': !!endIcon,
						'dsb_button__icon-button': !children,
					},
					className,
				)}
				disabled={disabled || loadingState === 'loading'}
			>
				<div
					className={classNames('dsb-button-progress__status', {
						'dsb-button-progress__status--show': isFinished,
					})}
				>
					<Icon iconName={statusIcon} size={size} />
				</div>

				<span
					className={classNames('dsb-button-progress__content', {
						'dsb-button-progress__content--hide': isFinished,
					})}
				>
					{startIcon && <div className="dsb_button-start-icon">{startIcon}</div>}
					{children}
					{endIcon && <div className="dsb_button-end-icon">{endIcon}</div>}
				</span>
				<svg
					ref={svgRef}
					width={`${settings.width + settings.strokeWidth}`}
					height={`${settings.height + settings.strokeWidth}`}
					className={classNames('dsb-button-progress__svg')}
					role="progressbar"
					aria-busy={loadingState === 'loading'}
				>
					<path
						ref={pathRef}
						className={classNames('dsb-button-progress__svg-path', `dsb-button-progress__svg-path--${loadingState}`, {
							'dsb-button-progress__svg-path--indeterminate-loading': !determinateMode && loadingState === 'loading',
						})}
						d={pathDefinition}
						strokeDasharray="100"
						strokeDashoffset={`${100 - _progress}`}
						pathLength="100"
						stroke={strokeColor}
					/>
				</svg>
			</Button>
		);
	},
);
